SELECT dbo.lpad(isnull(max(cast(right(lotno, 3) as int)) + 1, 1), 3, '0')
  from hpio200t_tbl
where cmpycd = #{cmpycd}
and linecd = #{linecd}
and itemcd = #{itemcd}
and lotymd = #{ordymd}

mapper.update:
update HPIO210T_TBL
   set ordqty = #{ordqty},
       lotsize = #{ordqty},
       updtime = getdate(),
       updemp = #{updemp}
 where cmpycd = #{cmpycd}
   and linecd = #{linecd}
   and progcd = #{progcd}
   and ordymd = #{ordymd}
   and lotno = #{lotno}
   and itemcd = #{itemcd}
   and isnull(ordno, '') = isnull(#{ordno}, '')

update HPIO200T_TBL
   set ordqty = #{ordqty},
       lotsize = #{ordqty},
       updtime = getdate(),
       updemp = #{updemp}
 where cmpycd = #{cmpycd}
   and linecd = #{linecd}
   and lotymd = #{ordymd}
   and lotno = #{lotno}
   and itemcd = #{itemcd}
   and isnull(ordno, '') = isnull(#{ordno}, '')

update HPPL160T_TBL
   set ordqty = isnull(ordqty, 0) + #{qty}
 where cmpycd = #{cmpycd}
   and yymmdd = #{yymmdd}
   and ser    = #{ser}
   and itemcd = #{itemcd}

